const mongoose = require('mongoose');
require('dotenv').config();

const profileSchema = new mongoose.Schema({
  name: String,
  title: String,
  bio: String,
  profileImage: String
});

const Profile = mongoose.model('Profile', profileSchema);

const projectSchema = new mongoose.Schema({
  title: String,
  description: String,
  technologies: [String],
  image: String
});

const Project = mongoose.model('Project', projectSchema);

const seedProjects = [
  {
    title: 'CivicFix',
    description: 'CivicFix is a mobile application that enables citizens to report civic issues such as potholes, garbage accumulation, and damaged streetlights. Users can upload images, track complaint status, and receive real-time notifications. I developed the application using Flutter and Firebase, handling the frontend, database integration, authentication, and notification features.',
    technologies: ['Flutter', 'Firebase', 'FCM'],
    image: 'https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?auto=format&fit=crop&q=80&w=800'
  },
  {
    title: 'ProctAI',
    description: 'ProctAI is an AI-powered online examination platform designed to improve exam security. The system uses the YOLOv8n model to monitor students through a webcam and detect suspicious activities such as multiple people or unauthorized objects. My role involved developing the web application and integrating the AI model for real-time monitoring.',
    technologies: ['React', 'Python', 'YOLOv8n'],
    image: 'https://images.unsplash.com/photo-1488590528505-98d2b5aba04b?auto=format&fit=crop&q=80&w=800'
  },
  {
    title: 'Style Hive',
    description: 'Style Hive is a responsive fashion e-commerce website developed to provide users with an intuitive online shopping experience. The platform features product browsing, responsive design, and Firebase integration for backend services. I worked on designing the user interface, implementing frontend functionality, and ensuring the website was optimized for different devices and screen sizes.',
    technologies: ['HTML', 'CSS', 'JavaScript', 'Firebase'],
    image: 'https://images.unsplash.com/photo-1441984904996-e0b6ba687e04?auto=format&fit=crop&q=80&w=800'
  }
];


const placeholderBase64 = "data:image/jpeg;base64,";

const seedProfile = {
  name: 'Abhishek',
  title: 'Full-Stack Developer',
  bio: 'I\'m a Full-Stack Developer specializing in modern web and mobile applications.',
  profileImage: placeholderBase64 // You can replace this with your actual base64 string
};

const seedDB = async () => {
  try {
    await mongoose.connect(process.env.MONGODB_URI);
    console.log('Connected to MongoDB Atlas');

    // Clear existing data
    await Project.deleteMany({});
    await Profile.deleteMany({});
    console.log('Cleared existing projects and profile');

    // Insert new data
    await Project.insertMany(seedProjects);
    await Profile.create(seedProfile);
    console.log('Database seeded with projects and profile!');

    mongoose.connection.close();
  } catch (err) {
    console.error('Error seeding database:', err);
    mongoose.connection.close();
  }
};

seedDB();
